        print(self.par_1, self.par_2, self.par_a)

    def output(self):
        return luigi.LocalTarget('/tmp/log-{t.param_a}'.format(t=self))


class B(luigi.ExternalTask):
    """Second ext class"""
    par_b = luigi.Parameter(default="B")

    def run(self):
            print(self.par_1, self.par_2, self.par_b)

    def output(self):
        return luigi.LocalTarget('/tmp/log-{t.param_b}'.format(t=self))


@requires([A, B])
class C(luigi.Task):
    param_c = luigi.Parameter(default="c")

    def run(self):
        print(self.par_1, self.par_2, self.c)

    def output(self):
        return luigi.LocalTarget('/tmp/log-{t.param_c}'.format(t=self))

```

what do you think?

